+    // problematic case here is integer add with zero etc.
+    if (const auto *CI = dyn_cast<ConstantInt>(C)) {
+      switch (Opcode) {
+      case Instruction::Add:
+      case Instruction::Sub:
+        // Identity for add/sub is 0
+        return CI->isZero();
+      case Instruction::Mul:
+        // Identity for mul is 1
+        return CI->isOne();
+      case Instruction::And:
+        // Identity for and is all-ones
+        return CI->isMinusOne();
+      case Instruction::Or:
+        // Identity for or is 0
+        return CI->isZero();
+      case Instruction::Xor:
+        // Identity for xor is 0
+        return CI->isZero();
+      default:
+        break;
+      }
+    } else if (const auto *CFP = dyn_cast<ConstantFP>(C)) {
+      switch (Opcode) {
+      case Instruction::FAdd:
+      case Instruction::FSub:
+        // +0.0 is identity for floating add/sub
+        return CFP->isZero();
+      case Instruction::FMul:
+        // 1.0 is identity for floating mul
+        return CFP->isExactlyValue(1.0);
+      default:
+        break;
+      }
+    }
+    return false;
+  };
+
+  auto IsLoopInvariantIdentity = [&](Instruction *I) -> bool {
+    if (!I) return false;
+    unsigned Op = I->getOpcode();
+    if (I->getNumOperands() != 2)
+      return false;
+    Value *A = I->getOperand(0);
+    Value *B = I->getOperand(1);
+    // If either operand is loop-invariant identity constant, it's degenerate.
+    if (auto *C = dyn_cast<Constant>(A))
+      if (IsIdentityForOpcode(Op, C))
+        return true;
+    if (auto *C = dyn_cast<Constant>(B))
+      if (IsIdentityForOpcode(Op, C))
+        return true;
+    return false;
+  };
+
   // The Loop must be in LCSSA form.
   if (!L->isLCSSAForm(*DT))
     return false;
@@
-  if (!isMatchingOps(RdxDesc, Phi))
+  if (!isMatchingOps(RdxDesc, Phi))
     return false;

+  // If the recurrence operation is combined with an identity element only,
+  // we must not treat it as a reduction.
+  if (IsLoopInvariantIdentity(RdxDesc))
+    return false;
+
